args.sparql:
SELECT ?housePartyLabel ?senatePartyLabel WHERE {
  # Find House Majority Party via Speaker's party
  {
    SELECT ?partyLabel WHERE {
      ?speaker p:P39 ?stmt1 .
      ?stmt1 ps:P39 wd:Q912994 ; # Speaker of the US House
             pq:P580 ?start ;
             pq:P582 ?end .
      FILTER(?start <= "2012-12-31T00:00:00Z"^^xsd:dateTime && 
             ?end >= "2012-01-01T00:00:00Z"^^xsd:dateTime)
      ?speaker wdt:P102 ?party .
      ?party rdfs:label ?partyLabel .
      FILTER(LANG(?partyLabel) = 'en')
    }
    LIMIT 1
  } AS ?housePartyLabel

  # Find Senate Majority Party via Majority Leader's party
  {
    SELECT ?partyLabel WHERE {
      ?leader p:P39 ?stmt2 .
      ?stmt2 ps:P39 wd:Q156383 ; # Senate Majority Leader position
             pq:P580 ?start ;
             pq:P582 ?end .
      FILTER(?start <= "2012-12-31T00:00:00Z"^^xsd:dateTime && 
             ?end >= "2012-01-01T00:00:00Z"^^xsd:dateTime)
      ?leader wdt:P102 ?party .
      ?party rdfs:label ?partyLabel .
      FILTER(LANG(?partyLabel) = 'en')
    }
    LIMIT 1
  } AS ?senatePartyLabel
}

SELECT ?housePartyLabel ?senatePartyLabel WHERE {
  # Find the House Majority Party via the Speaker's party in 2012
  {
    ?speaker p:P39 ?houseStmt .
    ?houseStmt ps:P39 wd:Q912994 ;  # Speaker of the US House
             pq:P580 ?hsStart ;
             pq:P582 ?hsEnd .
    FILTER (?hsStart <= "2012-12-31"^^xsd:date && ?hsEnd >= "2012-01-01"^^xsd:date)
    ?speaker wdt:P102 ?houseParty .
    ?houseParty rdfs:label ?housePartyLabel .
    FILTER (LANG(?housePartyLabel) = 'en')
  }

  # Find the Senate Majority Party via Majority Leader's party in 2012
  {
    ?leader p:P39 ?senateStmt .
    ?senateStmt ps:P39 wd:Q156383 ;  # Senate Majority Leader
             pq:P580 ?senStart ;
             pq:P582 ?senEnd .
    FILTER (?senStart <= "2012-12-31"^^xsd:date && ?senEnd >= "2012-01-01"^^xsd:date)
    ?leader wdt:P102 ?senateParty .
    ?senateParty rdfs:label ?senatePartyLabel .
    FILTER (LANG(?senatePartyLabel) = 'en')
  }

  # Ensure we only get one result (since party is singular per chamber)

}

SELECT ?housePartyLabel ?senatePartyLabel WHERE {
  wd:Q170447 wdt:P2936 ?houseParty ;
             wdt:P2937 ?senateParty .
  ?houseParty rdfs:label ?housePartyLabel .
  ?senateParty rdfs:label ?senatePartyLabel .
  FILTER (LANG(?housePartyLabel) = 'en' && LANG(?senatePartyLabel) = 'en')
}
